import React, { useEffect, useState, useCallback } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { getPatients, deletePatient } from '../services/api';

export default function PatientList() {
  const [patients, setPatients] = useState([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState(null);
  const navigate = useNavigate();

  const fetchPatients = useCallback(async () => {
    setLoading(true);
    try {
      const res = await getPatients(search);
      setPatients(res.data.data);
    } catch { }
    setLoading(false);
  }, [search]);

  useEffect(() => {
    const t = setTimeout(fetchPatients, 300);
    return () => clearTimeout(t);
  }, [fetchPatients]);

  const handleDelete = async (id, name) => {
    if (!window.confirm(`Delete patient "${name}"? This also deletes all their visits and history.`)) return;
    setDeleting(id);
    await deletePatient(id).catch(() => {});
    fetchPatients();
    setDeleting(null);
  };

  const bloodBadge = (bt) => bt ? <span className="badge badge-blue">{bt}</span> : <span style={{ color: '#94a3b8' }}>—</span>;
  const genderBadge = (g) => g === 'Female' ? <span className="badge" style={{ background: '#fdf2f8', color: '#be185d' }}>F</span> : g === 'Male' ? <span className="badge badge-blue">M</span> : <span className="badge badge-orange">O</span>;

  return (
    <div>
      <div className="page-header">
        <div>
          <div className="page-title">Patients</div>
          <div className="page-subtitle">{patients.length} records{search ? ` matching "${search}"` : ''}</div>
        </div>
        <Link to="/patients/new" className="btn btn-primary">+ Add Patient</Link>
      </div>

      <div className="card" style={{ marginBottom: 20, padding: '12px 16px' }}>
        <input
          type="text"
          placeholder="Search by name, village or phone..."
          value={search}
          onChange={e => setSearch(e.target.value)}
          style={{ width: '100%', border: 'none', outline: 'none', fontSize: 14, color: '#1a202c', background: 'transparent' }}
        />
      </div>

      <div className="card">
        {loading ? (
          <div style={{ padding: 40, textAlign: 'center', color: '#64748b' }}>Loading patients...</div>
        ) : patients.length === 0 ? (
          <div className="empty-state">
            <div style={{ fontSize: 40, marginBottom: 8 }}>👥</div>
            <div style={{ fontWeight: 600, marginBottom: 4 }}>No patients found</div>
            <div style={{ fontSize: 12, marginBottom: 16 }}>Try a different search or add a new patient</div>
            <Link to="/patients/new" className="btn btn-primary">Add First Patient</Link>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr>
                  <th>#</th>
                  <th>Name</th>
                  <th>Age / Gender</th>
                  <th>Blood Type</th>
                  <th>Village</th>
                  <th>Phone</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {patients.map((p, i) => {
                  const age = Math.floor((new Date() - new Date(p.dob)) / (365.25 * 24 * 3600 * 1000));
                  return (
                    <tr key={p.id}>
                      <td style={{ color: '#94a3b8' }}>{i + 1}</td>
                      <td>
                        <div style={{ fontWeight: 600 }}>{p.name}</div>
                        <div style={{ fontSize: 11, color: '#94a3b8' }}>ID #{p.id}</div>
                      </td>
                      <td>{age}y {genderBadge(p.gender)}</td>
                      <td>{bloodBadge(p.blood_type)}</td>
                      <td>
                        <div>{p.village || '—'}</div>
                        {p.district && <div style={{ fontSize: 11, color: '#94a3b8' }}>{p.district}</div>}
                      </td>
                      <td style={{ color: '#2b7de9' }}>{p.phone || '—'}</td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <button className="btn btn-outline btn-sm" onClick={() => navigate(`/patients/${p.id}`)}>View</button>
                          <button className="btn btn-outline btn-sm" onClick={() => navigate(`/patients/${p.id}/edit`)}>Edit</button>
                          <button className="btn btn-danger btn-sm" onClick={() => handleDelete(p.id, p.name)} disabled={deleting === p.id}>Del</button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
